class JavaGatewayProxyClient:
    def __init__(
        self,
        settings: JavaGatewayProxySettings | None = None,
        http_client: httpx.AsyncClient | None = None,
    ) -> None:
        self._settings = settings or JavaGatewayProxySettings.from_env()
        self._owns_client = http_client is None
        self._http_client = http_client or httpx.AsyncClient(
            timeout=httpx.Timeout(self._settings.timeout_seconds),
            trust_env=self._settings.trust_env,
            follow_redirects=False,
        )

    def ensure_configured(self) -> None:
        if not self._settings.base_url:
            raise RuntimeError("JAVA_GATEWAY_BASE_URL is empty")

    async def request(
        self,
        *,
        method: str,
        path: str,
        query_string: str = "",
        headers: Iterable[tuple[str, str]] = (),
        content: bytes | None = None,
    ) -> httpx.Response:
        self.ensure_configured()
        normalized_path = path if path.startswith("/") else f"/{path}"
        upstream_url = f"{self._settings.base_url}{normalized_path}"
        if query_string:
            upstream_url = f"{upstream_url}?{query_string}"
        request_headers = {
            key: value
            for key, value in headers
            if key and value and key.lower() not in _HOP_BY_HOP_HEADERS
        }
        return await self._http_client.request(
            method=method.upper(),
            url=upstream_url,
            headers=request_headers,
            content=content,
        )

    async def aclose(self) -> None:
        if self._owns_client:
            await self._http_client.aclose()


