async def _proxy_java_gateway_request(
    request: Request,
    gateway_proxy: JavaGatewayProxyClient,
    upstream_path: str,
) -> Response:
    # 所有页面相关请求都按同域入口进入 Python，再原样透传到 Java，避免前端关心跨域和环境地址。
    try:
        upstream_response = await gateway_proxy.request(
            method=request.method,
            path=upstream_path,
            query_string=request.url.query,
            headers=request.headers.items(),
            content=await request.body(),
        )
    except RuntimeError as exc:
        raise HTTPException(status_code=503, detail=str(exc)) from exc
    except httpx.HTTPError as exc:
        raise HTTPException(status_code=502, detail=f"java gateway proxy failed: {exc}") from exc

    response_headers = {
        key: value
        for key, value in upstream_response.headers.items()
        if key.lower()
        not in {
            "content-length",
            "content-encoding",
            "transfer-encoding",
            "connection",
        }
    }
    return Response(
        content=upstream_response.content,
        status_code=upstream_response.status_code,
        headers=response_headers,
    )

