const requestWithCandidateStream = ({ url, method, data, headers, onHeaders, onEvent, onTask }) =>
	new Promise((resolve, reject) => {
		let settled = false
		let responseHeaders = {}
		let streamOpened = false
		const pushEvent = createSseChunkParser((event) => {
			streamOpened = true
			if (typeof onEvent === 'function') {
				onEvent(event)
			}
		})
		const finishResolve = (payload) => {
			if (settled) {
				return
			}
			settled = true
			resolve(payload)
		}
		const finishReject = (error) => {
			if (settled) {
				return
			}
			settled = true
			reject(error)
		}

		const requestTask = uni.request({
			url,
			method,
			data,
			timeout: 0,
			enableChunked: true,
			enableHttp2: true,
			responseType: 'arraybuffer',
			header: headers,
			success: (res) => {
				const statusCode = res.statusCode || 0
				if (statusCode < 200 || statusCode >= 300) {
					finishReject({
						statusCode,
						data: res.data,
						message: (res.data && (res.data.detail || res.data.msg)) || `request failed: ${statusCode}`
					})
					return
				}

				if (isEventStreamResponse(responseHeaders)) {
					finishResolve({
						mode: 'stream',
						headers: responseHeaders,
						streamOpened
					})
					return
				}

				try {
					finishResolve({
						mode: 'json',
						headers: responseHeaders,
						data: normalizeAiSuccessPayload(normalizeStreamFallbackPayload(res.data))
					})
				} catch (error) {
					finishReject(error)
				}
			},
			fail: (error) => {
				finishReject({
					statusCode: 0,
					data: null,
					code: 'network_error',
					message: (error && error.errMsg) || 'network error'
				})
			},
			complete: () => {}
		})
		if (typeof onTask === 'function') {
			onTask(requestTask)
		}

		if (!requestTask || typeof requestTask.onChunkReceived !== 'function') {
			if (requestTask && typeof requestTask.abort === 'function') {
				requestTask.abort()
			}
			finishReject(createStreamUnsupportedError())
			return
		}

		if (typeof requestTask.onHeadersReceived === 'function') {
			requestTask.onHeadersReceived((result = {}) => {
				responseHeaders = result.header || {}
				if (typeof onHeaders === 'function') {
					onHeaders(responseHeaders, result)
				}
			})
		}

		requestTask.onChunkReceived((result = {}) => {
			const chunkText = decodeArrayBufferToText(result.data)
			if (chunkText) {
				pushEvent(chunkText)
			}
		})
	})

const aiRequest = async ({ path, method = 'GET', data = undefined, headers = {} }) => {
	const baseUrl = getAiBaseUrl()
	const candidates = buildAiRequestCandidates(baseUrl, path)
	let lastError = null

	for (let index = 0; index < candidates.length; index += 1) {
		try {
			return await requestWithCandidate({
				url: candidates[index],
				method,
				data,
				headers: buildAiHeaders(headers)
			})
		} catch (error) {
			lastError = error
			if (index === candidates.length - 1 || (error.statusCode && error.statusCode !== 404)) {
				break
			}
		}
	}

	throw lastError || new Error('AI request failed')
}

const aiStreamRequest = async ({ path, method = 'GET', data = undefined, headers = {}, onHeaders, onEvent, onTask }) => {
	const baseUrl = getAiBaseUrl()
	const candidates = buildAiRequestCandidates(baseUrl, path)
	let lastError = null

	for (let index = 0; index < candidates.length; index += 1) {
		try {
			return await requestWithCandidateStream({
				url: candidates[index],
				method,
				data,
				headers: buildAiHeaders({
					Accept: EVENT_STREAM_CONTENT_TYPE,
					...headers
				}),
				onHeaders,
				onEvent,
				onTask
			})
		} catch (error) {
			lastError = error
			if (error && error.code === 'stream_unsupported') {
				break
			}
			if (index === candidates.length - 1 || (error.statusCode && error.statusCode !== 404)) {
				break
			}
		}
	}

	throw lastError || new Error('AI stream request failed')
}

