export const waitForAiConversationResult = async (conversationId, afterMessageId = 0, options = {}) => {
	const interval = options.interval || DEFAULT_POLL_INTERVAL
	const maxPollCount = options.maxPollCount || DEFAULT_MAX_POLL_COUNT
	let lastMessageId = afterMessageId

	for (let index = 0; index < maxPollCount; index += 1) {
		if (typeof options.shouldStop === 'function' && options.shouldStop()) {
			throw buildInterruptedError(lastMessageId)
		}
		const rawPayload = await getAiConversationMessages(conversationId, {
			afterMessageId: lastMessageId
		})
		const messages = parseAiMessages(rawPayload)

		if (messages.length) {
			lastMessageId = messages[messages.length - 1].id || lastMessageId
			if (typeof options.onMessages === 'function') {
				options.onMessages(messages, lastMessageId)
			}
			if (typeof options.shouldStop === 'function' && options.shouldStop()) {
				throw buildInterruptedError(lastMessageId)
			}

			const failureMessage = messages.find((item) => item.messageType === 'conversation_failed')
			if (failureMessage) {
				const envelope = normalizeAiMessageEnvelope(failureMessage)
				const error = new Error(envelope.payload.error || 'AI 助手调用失败')
				error.lastMessageId = lastMessageId
				error.messages = messages
				throw error
			}

			const terminalMessage = messages.find((item) =>
				TERMINAL_MESSAGE_TYPES.includes(item.messageType)
			)
			if (terminalMessage) {
				return {
					lastMessageId,
					messages,
